#!/usr/bin/env python3
"""
circopt - Circuit optimizer and validator
"""

import argparse
import json
import sys
from typing import Optional
from dataclasses import dataclass, field
from enum import Enum, auto


# ============================================================================
# Error Classes
# ============================================================================

class CircoptError(Exception):
    """Base exception for all circopt errors."""

    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message)
        self.message = message
        self.file = file
        self.line = line
        self.col = col

    def to_dict(self, command: str) -> dict:
        result = {
            "ok": False,
            "command": command,
            "exit_code": self.exit_code,
            "error": {
                "type": self.error_type,
                "message": self.message,
            }
        }
        if self.file is not None:
            result["error"]["file"] = self.file
        if self.line is not None:
            result["error"]["line"] = self.line
        if self.col is not None:
            result["error"]["col"] = self.col
        return result


class CliUsageError(CircoptError):
    exit_code = 1
    error_type = "CliUsageError"

    def __init__(self, message: str):
        super().__init__(message)


class CircParseError(CircoptError):
    exit_code = 2
    error_type = "CircParseError"

    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message, file, line, col)


class DeclarationAfterAssignmentError(CircoptError):
    exit_code = 3
    error_type = "DeclarationAfterAssignmentError"

    def __init__(self, message: str = "Declaration after assignment"):
        super().__init__(message)


class DuplicateNameError(CircoptError):
    exit_code = 3
    error_type = "DuplicateNameError"

    def __init__(self, name: str):
        super().__init__(f"Duplicate name: '{name}'")


class UndefinedNameError(CircoptError):
    exit_code = 3
    error_type = "UndefinedNameError"

    def __init__(self, name: str):
        super().__init__(f"Undefined name: '{name}'")


class UnassignedSignalError(CircoptError):
    exit_code = 3
    error_type = "UnassignedSignalError"

    def __init__(self, name: str):
        super().__init__(f"Unassigned signal: '{name}'")


class InputAssignmentError(CircoptError):
    exit_code = 3
    error_type = "InputAssignmentError"

    def __init__(self, name: str):
        super().__init__(f"Cannot assign to input: '{name}'")


class MultipleAssignmentError(CircoptError):
    exit_code = 3
    error_type = "MultipleAssignmentError"

    def __init__(self, name: str):
        super().__init__(f"Multiple assignment to: '{name}'")


class ArityError(CircoptError):
    exit_code = 3
    error_type = "ArityError"

    def __init__(self, op: str, expected: int, got: int):
        super().__init__(f"Arity error: {op} expects {expected}, got {got}")


class CycleError(CircoptError):
    exit_code = 3
    error_type = "CycleError"

    def __init__(self, path: list):
        cycle_str = " -> ".join(path)
        super().__init__(f"Cycle detected: {cycle_str}")


# ============================================================================
# AST Nodes
# ============================================================================

class NodeType(Enum):
    INPUT = auto()
    OUTPUT = auto()
    WIRE = auto()
    ASSIGNMENT = auto()
    IDENTIFIER = auto()
    LITERAL = auto()
    CALL = auto()


@dataclass
class Node:
    node_type: NodeType
    line: Optional[int] = None
    col: Optional[int] = None


@dataclass
class DeclarationNode(Node):
    names: list = field(default_factory=list)


@dataclass
class AssignmentNode(Node):
    lhs: str = ""
    rhs: 'ExprNode' = None  # type: ignore


@dataclass
class ExprNode(Node):
    value = ""
    args: list = field(default_factory=list)


# ============================================================================
# Tokenizer
# ============================================================================

class TokenType(Enum):
    IDENTIFIER = auto()
    NUMBER = auto()
    OP = auto()  # NOT, AND, OR, etc.
    EQUALS = auto()
    COMMA = auto()
    LPAREN = auto()
    RPAREN = auto()
    WHITESPACE = auto()
    COMMENT = auto()
    EOF = auto()


@dataclass
class Token:
    type: TokenType
    value: str
    line: int
    col: int


class Tokenizer:
    """Tokenizer for .circ files."""

    KEYWORDS = {'INPUT', 'OUTPUT', 'WIRE'}
    OPS = {'NOT', 'AND', 'OR', 'XOR', 'NAND', 'NOR', 'XNOR', 'BUF'}

    def __init__(self, text: str, filename: Optional[str] = None):
        self.text = text
        self.filename = filename
        self.pos = 0
        self.line = 1
        self.col = 1

    def peek(self) -> Optional[str]:
        if self.pos < len(self.text):
            return self.text[self.pos]
        return None

    def advance(self) -> str:
        ch = self.text[self.pos]
        self.pos += 1
        if ch == '\n':
            self.line += 1
            self.col = 1
        else:
            self.col += 1
        return ch

    def skip_whitespace_and_comments(self):
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isspace():
                self.advance()
            elif ch == '#':
                # Skip comment until end of line
                while self.pos < len(self.text) and self.peek() != '\n':
                    self.advance()
            else:
                break

    def tokenize_identifier(self, first_char: str) -> Token:
        """Tokenize an identifier (letters, digits, underscore)."""
        start_line = self.line
        start_col = self.col - len(first_char) - 1 if self.col > 1 else self.line
        value = first_char
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isalnum() or ch == '_':
                value += self.advance()
            else:
                break
        value_upper = value.upper()
        if value_upper in self.KEYWORDS:
            token_type = TokenType.OP  # Actually, keywords are treated as OP-like
        elif value_upper in self.OPS:
            token_type = TokenType.OP
        else:
            token_type = TokenType.IDENTIFIER
        return Token(token_type, value, start_line, start_col)

    def tokenize_number(self, first_char: str) -> Token:
        """Tokenize a number (0 or 1 in this context)."""
        start_line = self.line
        start_col = self.col - 1
        value = first_char
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isdigit():
                value += self.advance()
            else:
                break
        return Token(TokenType.NUMBER, value, start_line, start_col)

    def next_token(self) -> Token:
        self.skip_whitespace_and_comments()

        if self.pos >= len(self.text):
            return Token(TokenType.EOF, '', self.line, self.col)

        ch = self.peek()
        start_line = self.line
        start_col = self.col

        if ch.isalpha() or ch == '_':
            return self.tokenize_identifier(self.advance())
        elif ch.isdigit():
            return self.tokenize_number(self.advance())
        elif ch == '=':
            self.advance()
            return Token(TokenType.EQUALS, '=', start_line, start_col)
        elif ch == ',':
            self.advance()
            return Token(TokenType.COMMA, ',', start_line, start_col)
        elif ch == '(':
            self.advance()
            return Token(TokenType.LPAREN, '(', start_line, start_col)
        elif ch == ')':
            self.advance()
            return Token(TokenType.RPAREN, ')', start_line, start_col)
        else:
            raise CircParseError(
                f"Unexpected character: '{ch}'",
                self.filename, start_line, start_col
            )

    def tokenize(self) -> list:
        tokens = []
        while True:
            token = self.next_token()
            tokens.append(token)
            if token.type == TokenType.EOF:
                break
        return tokens


