#!/usr/bin/env python3
"""
circopt - Circuit optimizer and validator
"""

import argparse
import json
import sys
from typing import Optional
from dataclasses import dataclass, field
from enum import Enum, auto


# ============================================================================
# Error Classes
# ============================================================================

class CircoptError(Exception):
    """Base exception for all circopt errors."""

    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message)
        self.message = message
        self.file = file
        self.line = line
        self.col = col

    def to_dict(self, command: str) -> dict:
        result = {
            "ok": False,
            "command": command,
            "exit_code": self.exit_code,
            "error": {
                "type": self.error_type,
                "message": self.message,
            }
        }
        if self.file is not None:
            result["error"]["file"] = self.file
        if self.line is not None:
            result["error"]["line"] = self.line
        if self.col is not None:
            result["error"]["col"] = self.col
        return result


class CliUsageError(CircoptError):
    exit_code = 1
    error_type = "CliUsageError"

    def __init__(self, message: str):
        super().__init__(message)


class CircParseError(CircoptError):
    exit_code = 2
    error_type = "CircParseError"

    def __init__(self, message: str, file: Optional[str] = None,
                 line: Optional[int] = None, col: Optional[int] = None):
        super().__init__(message, file, line, col)


class DeclarationAfterAssignmentError(CircoptError):
    exit_code = 3
    error_type = "DeclarationAfterAssignmentError"

    def __init__(self, message: str = "Declaration after assignment"):
        super().__init__(message)


class DuplicateNameError(CircoptError):
    exit_code = 3
    error_type = "DuplicateNameError"

    def __init__(self, name: str):
        super().__init__(f"Duplicate name: '{name}'")


class UndefinedNameError(CircoptError):
    exit_code = 3
    error_type = "UndefinedNameError"

    def __init__(self, name: str):
        super().__init__(f"Undefined name: '{name}'")


class UnassignedSignalError(CircoptError):
    exit_code = 3
    error_type = "UnassignedSignalError"

    def __init__(self, name: str):
        super().__init__(f"Unassigned signal: '{name}'")


class InputAssignmentError(CircoptError):
    exit_code = 3
    error_type = "InputAssignmentError"

    def __init__(self, name: str):
        super().__init__(f"Cannot assign to input: '{name}'")


class MultipleAssignmentError(CircoptError):
    exit_code = 3
    error_type = "MultipleAssignmentError"

    def __init__(self, name: str):
        super().__init__(f"Multiple assignment to: '{name}'")


class ArityError(CircoptError):
    exit_code = 3
    error_type = "ArityError"

    def __init__(self, op: str, expected: int, got: int):
        super().__init__(f"Arity error: {op} expects {expected}, got {got}")


class CycleError(CircoptError):
    exit_code = 3
    error_type = "CycleError"

    def __init__(self, path: list):
        cycle_str = " -> ".join(path)
        super().__init__(f"Cycle detected: {cycle_str}")


# ============================================================================
# AST Nodes
# ============================================================================

class NodeType(Enum):
    INPUT = auto()
    OUTPUT = auto()
    WIRE = auto()
    ASSIGNMENT = auto()
    IDENTIFIER = auto()
    LITERAL = auto()
    CALL = auto()


@dataclass
class Node:
    node_type: NodeType
    line: Optional[int] = None
    col: Optional[int] = None


@dataclass
class DeclarationNode(Node):
    names: list = field(default_factory=list)


@dataclass
class AssignmentNode(Node):
    lhs: str = ""
    rhs: 'ExprNode' = None  # type: ignore


@dataclass
class ExprNode(Node):
    value = ""
    args: list = field(default_factory=list)


# ============================================================================
# Tokenizer
# ============================================================================

class TokenType(Enum):
    IDENTIFIER = auto()
    NUMBER = auto()
    OP = auto()  # NOT, AND, OR, etc.
    EQUALS = auto()
    COMMA = auto()
    LPAREN = auto()
    RPAREN = auto()
    WHITESPACE = auto()
    COMMENT = auto()
    EOF = auto()


@dataclass
class Token:
    type: TokenType
    value: str
    line: int
    col: int


class Tokenizer:
    """Tokenizer for .circ files."""

    KEYWORDS = {'INPUT', 'OUTPUT', 'WIRE'}
    OPS = {'NOT', 'AND', 'OR', 'XOR', 'NAND', 'NOR', 'XNOR', 'BUF'}

    def __init__(self, text: str, filename: Optional[str] = None):
        self.text = text
        self.filename = filename
        self.pos = 0
        self.line = 1
        self.col = 1

    def peek(self) -> Optional[str]:
        if self.pos < len(self.text):
            return self.text[self.pos]
        return None

    def advance(self) -> str:
        ch = self.text[self.pos]
        self.pos += 1
        if ch == '\n':
            self.line += 1
            self.col = 1
        else:
            self.col += 1
        return ch

    def skip_whitespace_and_comments(self):
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isspace():
                self.advance()
            elif ch == '#':
                # Skip comment until end of line
                while self.pos < len(self.text) and self.peek() != '\n':
                    self.advance()
            else:
                break

    def tokenize_identifier(self, first_char: str) -> Token:
        """Tokenize an identifier (letters, digits, underscore)."""
        start_line = self.line
        start_col = self.col - len(first_char) - 1 if self.col > 1 else self.line
        value = first_char
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isalnum() or ch == '_':
                value += self.advance()
            else:
                break
        value_upper = value.upper()
        if value_upper in self.KEYWORDS:
            token_type = TokenType.OP  # Actually, keywords are treated as OP-like
        elif value_upper in self.OPS:
            token_type = TokenType.OP
        else:
            token_type = TokenType.IDENTIFIER
        return Token(token_type, value, start_line, start_col)

    def tokenize_number(self, first_char: str) -> Token:
        """Tokenize a number (0 or 1 in this context)."""
        start_line = self.line
        start_col = self.col - 1
        value = first_char
        while self.pos < len(self.text):
            ch = self.peek()
            if ch.isdigit():
                value += self.advance()
            else:
                break
        return Token(TokenType.NUMBER, value, start_line, start_col)

    def next_token(self) -> Token:
        self.skip_whitespace_and_comments()

        if self.pos >= len(self.text):
            return Token(TokenType.EOF, '', self.line, self.col)

        ch = self.peek()
        start_line = self.line
        start_col = self.col

        if ch.isalpha() or ch == '_':
            return self.tokenize_identifier(self.advance())
        elif ch.isdigit():
            return self.tokenize_number(self.advance())
        elif ch == '=':
            self.advance()
            return Token(TokenType.EQUALS, '=', start_line, start_col)
        elif ch == ',':
            self.advance()
            return Token(TokenType.COMMA, ',', start_line, start_col)
        elif ch == '(':
            self.advance()
            return Token(TokenType.LPAREN, '(', start_line, start_col)
        elif ch == ')':
            self.advance()
            return Token(TokenType.RPAREN, ')', start_line, start_col)
        else:
            raise CircParseError(
                f"Unexpected character: '{ch}'",
                self.filename, start_line, start_col
            )

    def tokenize(self) -> list:
        tokens = []
        while True:
            token = self.next_token()
            tokens.append(token)
            if token.type == TokenType.EOF:
                break
        return tokens


# ============================================================================
# Parser
# ============================================================================

class Parser:
    """Parser for .circ files."""

    def __init__(self, tokens: list, filename: Optional[str] = None):
        self.tokens = tokens
        self.filename = filename
        self.pos = 0

    def peek(self) -> Optional[Token]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type: TokenType, value: Optional[str] = None) -> Token:
        token = self.peek()
        if token is None:
            raise CircParseError(
                f"Unexpected end of file",
                self.filename, self.tokens[-1].line if self.tokens else 1,
                self.tokens[-1].col if self.tokens else 1
            )
        if token.type != expected_type:
            raise CircParseError(
                f"Expected {expected_type.name}, got {token.type.name}: '{token.value}'",
                self.filename, token.line, token.col
            )
        self.pos += 1
        return token

    def parse_identifier(self) -> Token:
        token = self.consume(TokenType.IDENTIFIER)
        return token

    def parse_expr(self) -> ExprNode:
        """Parse an expression."""
        token = self.peek()
        if token is None:
            raise CircParseError("Unexpected end of file in expression", self.filename)

        if token.type == TokenType.IDENTIFIER:
            self.pos += 1
            return ExprNode(NodeType.IDENTIFIER, token.line, token.col, token.value)
        elif token.type == TokenType.NUMBER:
            self.pos += 1
            # Validate it's 0 or 1
            if token.value not in ('0', '1'):
                raise CircParseError(
                    f"Invalid literal: {token.value}. Only 0 and 1 are allowed.",
                    self.filename, token.line, token.col
                )
            return ExprNode(NodeType.LITERAL, token.line, token.col, token.value)
        elif token.type == TokenType.OP:
            return self.parse_call()
        else:
            raise CircParseError(
                f"Unexpected token in expression: {token.type.name}: '{token.value}'",
                self.filename, token.line, token.col
            )

    def parse_call(self) -> ExprNode:
        """Parse a function call like AND(a, b)."""
        op_token = self.consume(TokenType.OP)
        op_name = op_token.value.upper()

        self.consume(TokenType.LPAREN)

        args = []
        while True:
            arg = self.parse_expr()
            args.append(arg)

            next_token = self.peek()
            if next_token is None:
                raise CircParseError(
                    f"Unexpected end of file, expected ')'",
                    self.filename, op_token.line, op_token.col
                )
            if next_token.type == TokenType.RPAREN:
                break
            elif next_token.type == TokenType.COMMA:
                self.pos += 1
                continue
            else:
                raise CircParseError(
                    f"Expected ',' or ')', got {next_token.type.name}: '{next_token.value}'",
                    self.filename, next_token.line, next_token.col
                )

        self.consume(TokenType.RPAREN)

        return ExprNode(NodeType.CALL, op_token.line, op_token.col, op_name, args)

    def parse_declaration(self) -> DeclarationNode:
        """Parse a declaration line: input a b c, output y, wire t1 t2."""
        type_token = self.consume(TokenType.OP)
        type_upper = type_token.value.upper()

        names = []
        while True:
            token = self.peek()
            if token is None or token.type == TokenType.EOF:
                break
            if token.type == TokenType.IDENTIFIER:
                self.pos += 1
                names.append(token.value)
            else:
                break

        if not names:
            raise CircParseError(
                f"Expected names after declaration type",
                self.filename, type_token.line, type_token.col
            )

        node = DeclarationNode(NodeType.INPUT if type_upper == "INPUT" else
                               NodeType.OUTPUT if type_upper == "OUTPUT" else NodeType.WIRE,
                               type_token.line, type_token.col)
        node.names = names
        return node

    def parse_assignment(self) -> AssignmentNode:
        """Parse an assignment line: lhs = rhs."""
        lhs_token = self.consume(TokenType.IDENTIFIER)
        lhs = lhs_token.value

        self.consume(TokenType.EQUALS)

        rhs = self.parse_expr()

        # Check for unexpected tokens after expression
        next_token = self.peek()
        if next_token and next_token.type != TokenType.EOF:
            # Try to handle gracefully - if there's more, it's an error
            pass  # Let validation handle issues

        return AssignmentNode(NodeType.ASSIGNMENT, lhs_token.line, lhs_token.col, lhs, rhs)

    def parse_line(self) -> Optional[Node]:
        """Parse a single line, returning None for empty lines."""
        # Skip leading whitespace
        self.skip_whitespace_before_parse()

        token = self.peek()
        if token is None or token.type == TokenType.EOF:
            return None

        # Check if this is a declaration or assignment
        if token.type == TokenType.OP:
            op_upper = token.value.upper()
            if op_upper in ('INPUT', 'OUTPUT', 'WIRE'):
                return self.parse_declaration()

        # Default to assignment
        return self.parse_assignment()

    def skip_whitespace_before_parse(self):
        """Skip whitespace before parsing a line."""
        while self.pos < len(self.tokens):
            token = self.tokens[self.pos]
            if token.type in (TokenType.WHITESPACE, TokenType.COMMENT):
                self.pos += 1
            else:
                break

    def parse(self) -> list:
        """Parse the entire file."""
        statements = []
        while self.pos < len(self.tokens):
            stmt = self.parse_line()
            if stmt is not None:
                statements.append(stmt)
        return statements


# ============================================================================
# Validator
# ============================================================================

@dataclass
class Circuit:
    """Represents a parsed and validated circuit."""
    inputs: list = field(default_factory=list)   # list of str
    outputs: list = field(default_factory=list)  # list of str
    wires: list = field(default_factory=list)    # list of str
    assignments: dict = field(default_factory=dict)  # name -> ExprNode
    all_signals: set = field(default_factory=set)


class Validator:
    """Validates parsed circuit statements."""

    SUPPORTED_OPS = {
        'NOT': 1,
        'BUF': 1,
        'AND': 2,
        'OR': 2,
        'XOR': 2,
        'NAND': 2,
        'NOR': 2,
        'XNOR': 2,
    }

    def __init__(self, filename: Optional[str] = None):
        self.filename = filename
        self.circuit = Circuit()
        self.assignments_seen = False  # Have we seen any assignment yet?

    def validate(self, statements: list) -> Circuit:
        """Validate all statements and return the circuit."""
        # First pass: collect declarations
        for stmt in statements:
            if isinstance(stmt, DeclarationNode):
                if self.assignments_seen:
                    raise DeclarationAfterAssignmentError(
                        f"Declaration after assignment: '{stmt.names[0]}'"
                    )
                self._process_declaration(stmt)

        # Second pass: process assignments
        for stmt in statements:
            if isinstance(stmt, AssignmentNode):
                self.assignments_seen = True
                self._process_assignment(stmt)

        # Check that all signals are assigned
        self._check_all_assigned()

        # Check for cycles
        self._check_cycles()

        return self.circuit

    def _process_declaration(self, decl: DeclarationNode):
        """Process a declaration statement."""
        for name in decl.names:
            if name in self.circuit.all_signals:
                raise DuplicateNameError(name)

            self.circuit.all_signals.add(name)

            if decl.node_type == NodeType.INPUT:
                self.circuit.inputs.append(name)
            elif decl.node_type == NodeType.OUTPUT:
                self.circuit.outputs.append(name)
            else:  # WIRE
                self.circuit.wires.append(name)

    def _process_assignment(self, assign: AssignmentNode):
        """Process an assignment statement."""
        lhs = assign.lhs

        # Check LHS is declared
        if lhs not in self.circuit.all_signals:
            raise UndefinedNameError(lhs)

        # Check LHS is not an input
        if lhs in self.circuit.inputs:
            raise InputAssignmentError(lhs)

        # Check not already assigned
        if lhs in self.circuit.assignments:
            raise MultipleAssignmentError(lhs)

        # Validate the RHS expression
        self._validate_expr(assign.rhs)

        self.circuit.assignments[lhs] = assign.rhs

    def _validate_expr(self, expr: ExprNode):
        """Validate an expression."""
        if expr.node_type == NodeType.IDENTIFIER:
            # Identifier must be defined
            if expr.value not in self.circuit.all_signals:
                raise UndefinedNameError(expr.value)
        elif expr.node_type == NodeType.LITERAL:
            # Already validated to be 0 or 1 during parsing
            pass
        elif expr.node_type == NodeType.CALL:
            op = expr.value.upper()
            if op not in self.SUPPORTED_OPS:
                raise CircParseError(
                    f"Unknown operator: {op}",
                    self.filename, expr.line, expr.col
                )

            expected_arity = self.SUPPORTED_OPS[op]
            got_arity = len(expr.args)

            # Check arity
            if op in ('AND', 'OR', 'XOR', 'NAND', 'NOR', 'XNOR'):
                if got_arity < expected_arity:
                    raise ArityError(op, f"≥ {expected_arity}", got_arity)
            else:
                if got_arity != expected_arity:
                    raise ArityError(op, expected_arity, got_arity)

            # Validate all arguments
            for arg in expr.args:
                self._validate_expr(arg)

    def _check_all_assigned(self):
        """Check that all wires and outputs are assigned."""
        for name in self.circuit.wires + self.circuit.outputs:
            if name not in self.circuit.assignments:
                raise UnassignedSignalError(name)

    def _check_cycles(self):
        """Check for cycles in the assignment graph."""
        visited = set()
        rec_stack = set()
        path = []

        def dfs(node: str):
            visited.add(node)
            rec_stack.add(node)
            path.append(node)

            if node in self.circuit.assignments:
                expr = self.circuit.assignments[node]
                # Get all identifiers in the expression
                deps = self._get_identifiers(expr)
                for dep in deps:
                    if dep not in self.circuit.all_signals:
                        continue
                    if dep not in visited:
                        if dfs(dep):
                            return True
                    elif dep in rec_stack:
                        # Found a cycle
                        cycle_start = path.index(dep)
                        cycle_path = path[cycle_start:] + [dep]
                        raise CycleError(cycle_path)

            path.pop()
            rec_stack.remove(node)
            return False

        # Start DFS from each unvisited node that's an output or wire
        for name in self.circuit.outputs + self.circuit.wires:
            if name not in visited:
                if dfs(name):
                    return

    def _get_identifiers(self, expr: ExprNode) -> list:
        """Get all identifier names in an expression."""
        if expr.node_type == NodeType.IDENTIFIER:
            return [expr.value]
        elif expr.node_type == NodeType.LITERAL:
            return []
        elif expr.node_type == NodeType.CALL:
            result = []
            for arg in expr.args:
                result.extend(self._get_identifiers(arg))
            return result
        return []


# ============================================================================
# Main Application
# ============================================================================

VERSION = "0.1.0"


def print_json_error(command: str, error: CircoptError) -> str:
    """Print error in JSON format."""
    return json.dumps(error.to_dict(command))


def print_json_success(command: str, data: dict) -> str:
    """Print success in JSON format."""
    result = {"ok": True, "command": command}
    result.update(data)
    return json.dumps(result)


def check_command(args) -> int:
    """Implement the 'check' command."""
    filename = args.file

    # Read file
    try:
        with open(filename, 'r') as f:
            text = f.read()
    except FileNotFoundError:
        error = CliUsageError(f"File not found: {filename}")
        print(print_json_error("check", error), file=sys.stderr)
        return 1

    # Tokenize
    tokenizer = Tokenizer(text, filename)
    try:
        tokens = tokenizer.tokenize()
    except CircParseError as e:
        if e.file is None:
            e.file = filename
        print(print_json_error("check", e), file=sys.stderr)
        return e.exit_code

    # Parse
    parser = Parser(tokens, filename)
    try:
        statements = parser.parse()
    except CircParseError as e:
        if e.file is None:
            e.file = filename
        print(print_json_error("check", e), file=sys.stderr)
        return e.exit_code

    # Validate
    validator = Validator(filename)
    try:
        circuit = validator.validate(statements)
    except CircoptError as e:
        print(print_json_error("check", e), file=sys.stderr)
        return e.exit_code

    # Success - output circuit interface
    inputs = sorted([{"name": name, "msb": 0, "lsb": 0} for name in circuit.inputs],
                    key=lambda x: x["name"])
    outputs = sorted([{"name": name, "msb": 0, "lsb": 0} for name in circuit.outputs],
                     key=lambda x: x["name"])

    result = {
        "format": "circ",
        "inputs": inputs,
        "outputs": outputs,
    }

    print(print_json_success("check", result))
    return 0


def version_command(args) -> int:
    """Handle --version flag."""
    if args.json:
        result = {"version": VERSION}
        print(print_json_success("__version__", result))
    else:
        print(VERSION)
    return 0


def main() -> int:
    """Main entry point."""
    parser = argparse.ArgumentParser(
        prog='circopt',
        description='Circuit optimizer and validator',
        add_help=False,
    )

    # Global flags
    parser.add_argument('--help', action='store_true', help='Show help message')
    parser.add_argument('--version', action='store_true', help='Show version')
    parser.add_argument('--json', action='store_true', help='Output in JSON format')

    # Parse known args to check for command
    args, remaining = parser.parse_known_args(sys.argv[1:])

    # Handle --help
    if args.help:
        if args.json:
            # JSON mode - still print plain text help to stdout
            parser.print_help()
        else:
            parser.print_help()
        return 0

    # Handle --version
    if args.version:
        return version_command(args)

    # Check if there's a command
    if not remaining:
        error = CliUsageError("No command specified. Use 'check <file.circ>' to validate a circuit file.")
        print(print_json_error("__cli__", error), file=sys.stderr)
        return 1

    command = remaining[0]

    if command == 'check':
        # Parse check-specific args
        check_parser = argparse.ArgumentParser(prog='circopt check', add_help=False)
        check_parser.add_argument('file', help='Circuit file to check')
        check_parser.add_argument('--json', action='store_true', help='Output in JSON format')

        check_args, _ = check_parser.parse_known_args(remaining[1:])
        return check_command(check_args)
    else:
        error = CliUsageError(f"Unknown command: {command}")
        print(print_json_error("__cli__", error), file=sys.stderr)
        return 1


if __name__ == '__main__':
    sys.exit(main())
